15	// runScriptFn executes a directive file against opts.WorkDir using real filesystem
16	// and git operations. The directive file path is taken from opts.Model (if it is
17	// a readable file) or from opts.PromptFile as a fallback.
18	func runScriptFn(r *Runner, opts RunOptions) (*Result, error) {
19		start := time.Now()
20	
21		// Resolve directive file: opts.Model first, then opts.PromptFile.
22		directivePath := opts.Model
23		if directivePath == "" || !isReadableFile(directivePath) {
24			if opts.PromptFile != "" {
25				directivePath = opts.PromptFile
26			}
27		}
28		if directivePath == "" {
29			return nil, fmt.Errorf("script harness: no directive file (set --model or --prompt-file)")
30		}
31	
32		data, err := os.ReadFile(directivePath)
33		if err != nil {
34			return nil, fmt.Errorf("script harness: read directive file %s: %w", directivePath, err)
35		}
36	
37		workDir := opts.WorkDir
38		if workDir == "" {
39			workDir = "."
40		}
41	
42		var outputLines []string
43		exitCode := 0
44		var execErr error
45	
46		directives := parseDirectives(string(data))
47	
48		// Build env interpolation map from Correlation.
49		envMap := map[string]string{
50			"DDX_BEAD_ID":    "",
51			"DDX_ATTEMPT_ID": "",
52			"DDX_WORKER_ID":  "",
53		}
54		if opts.Correlation != nil {
55			if v, ok := opts.Correlation["bead_id"]; ok {
56				envMap["DDX_BEAD_ID"] = v
57			}
58			if v, ok := opts.Correlation["attempt_id"]; ok {
59				envMap["DDX_ATTEMPT_ID"] = v
60			}
61			if v, ok := opts.Correlation["worker_id"]; ok {
62				envMap["DDX_WORKER_ID"] = v
63			}
64		}
65		expand := func(s string) string {
66			return os.Expand(s, func(key string) string {
67				return envMap[key]
68			})
69		}
70	
71		for i, d := range directives {
72			verb := d[0]
73			args := d[1:]
74	
75			switch verb {
76			case "no-op":
77				outputLines = append(outputLines, "no-op")
78	
79			case "set-exit":
80				if len(args) < 1 {
81					execErr = fmt.Errorf("script harness: set-exit requires an argument")
82					goto done
83				}
84				n, err := strconv.Atoi(args[0])
85				if err != nil {
86					execErr = fmt.Errorf("script harness: set-exit: invalid code %q", args[0])
87					goto done
88				}
89				exitCode = n
90	
91			case "sleep-ms":
92				if len(args) < 1 {
93					execErr = fmt.Errorf("script harness: sleep-ms requires an argument")
94					goto done
95				}
96				n, err := strconv.Atoi(args[0])
97				if err != nil {
98					execErr = fmt.Errorf("script harness: sleep-ms: invalid duration %q", args[0])
99					goto done
100				}
101				time.Sleep(time.Duration(n) * time.Millisecond)
102	
103			case "fail-during":
104				if len(args) < 1 {
105					execErr = fmt.Errorf("script harness: fail-during requires an argument")
106					goto done
107				}
108				n, err := strconv.Atoi(args[0])
109				if err != nil {
110					execErr = fmt.Errorf("script harness: fail-during: invalid index %q", args[0])
111					goto done
112				}
113				if i == n {
114					execErr = fmt.Errorf("script harness: synthetic failure at directive %d", i)
115					goto done
116				}
117	
118			case "append-line":
