330	// gitCommitAll runs git add -A && git commit -m msg in dir with scrubbed GIT_* env.
331	func gitCommitAll(dir, msg string) error {
332		for _, args := range [][]string{
333			{"add", "-A"},
334			{"commit", "-m", msg},
335		} {
336			cmd := exec.Command("git", args...)
337			cmd.Dir = dir
338			cmd.Env = scrubbedGitEnvScript()
339			if out, err := cmd.CombinedOutput(); err != nil {
340				return fmt.Errorf("git %v: %w\n%s", args, err, out)
341			}
342		}
343		return nil
344	}
